func (h *HasBytesWriter) Write(p []byte) (n int, err error) {
	if h.done {
		return len(p), nil
	}

	if len(h.buff) == 0 {
		h.buff = make([]byte, h.patternLen()*2)
	}

	for i := range p {
		h.buff[h.i] = p[i]
		h.i++
		if h.i == len(h.buff) {

			copy(h.buff, h.buff[len(h.buff)/2:])
			h.i = len(h.buff) / 2
		}

		for _, pp := range h.Patterns {
			if bytes.Contains(h.buff, pp.Pattern) {
				pp.Match = true
				done := true
				for _, ppp := range h.Patterns {
					if !ppp.Match {
						done = false
						break
					}
				}
				if done {
					h.done = true
				}
				return len(p), nil
			}
		}

	}

	return len(p), nil
}
